import zxcvbn from"zxcvbn";const StrengthMapping={0:{class:"danger",width:"10%",status:"非常弱"},1:{class:"danger",width:"25%",status:"非常弱"},2:{class:"warning",width:"50%",status:"弱"},3:{class:"success",width:"75%",status:"良好"},4:{class:"success",width:"100%",status:"非常强"}},Progress=document.getElementById("password-strength-container"),ProgressBar=document.getElementById("password-strength-bar"),StrengthDescription=document.getElementById("password-strength-description"),updatePasswordStrength=s=>{const t=s.target.value;if(!t)return ProgressBar.style.width=0,StrengthDescription.textContent="",void Progress.classList.add("hidden");const e=zxcvbn(t).score,r=StrengthMapping[e];ProgressBar.classList=`progress-bar progress-bar-${r.class}`,ProgressBar.style.width=r.width,StrengthDescription.textContent=r.status,StrengthDescription.classList=`text-${r.class}`,Progress.classList.remove("hidden")};document.getElementById("password").addEventListener("input",updatePasswordStrength);